// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentRawEvent) predicate.AgentRawEvent {
	return predicate.AgentRawEvent(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentRawEvent) predicate.AgentRawEvent {
	return predicate.AgentRawEvent(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentRawEvent) predicate.AgentRawEvent {
	return predicate.AgentRawEvent(sql.NotPredicates(p))
}
